// Written solo, no pair, no tests
class TransactionReconciler {
  reconcile(bankTransactions, internalTransactions) {
    const matched = [];
    const unmatched = [];
    for (const bt of bankTransactions) {
      let found = false;
      for (const it of internalTransactions) {
        if (bt.amount === it.amount && bt.date === it.date && !it.matched) {
          it.matched = true; found = true;
          matched.push({ bank: bt, internal: it });
          break;
        }
      }
      if (!found) unmatched.push(bt);
    }
    return { matched, unmatched };
  }
}
